{
  "steps": [
    {
      "step_id": "cb_step_1",
      "title": "Select CT Volume",
      "simple": "Choose the CT scan that will be used for bone analysis and planning.",
      "detailed": "This CT volume provides the bone density information needed for prosthetic planning. Selecting the correct scan ensures the bone segmentation and screw path calculations are based on the patient's anatomy. In the 'CT volume - bone density for optimization' section, pick the appropriate CT series from the list."
    },
    {
      "step_id": "cb_step_2",
      "title": "Create a New Bone Segmentation",
      "simple": "In the Segment Editor, create a new segmentation and name it 'Bone_Segmentation'.",
      "detailed": "This segmentation will hold the bone mask that isolates bone from soft tissue. Accurate bone segmentation is critical for later 3D reconstruction and screw planning. Go to the Segment Editor module and create a new segmentation, renaming it to 'Bone_Segmentation'."
    },
    {
      "step_id": "cb_step_3",
      "title": "Add a Segment for Bone",
      "simple": "Click the 'Add' button in the Segment Editor and rename the new segment to 'Bone_Segment'.",
      "detailed": "This segment will contain the bone volume extracted via thresholding. Naming it clearly helps organize multiple potential segments. Click 'Add', then right-click or double-click the segment name to rename it to 'Bone_Segment'."
    },
    {
      "step_id": "cb_step_4",
      "title": "Open Threshold Tool",
      "simple": "In the Segment Editor, click the 'Threshold' button to prepare for bone density thresholding.",
      "detailed": "Thresholding will separate bone from other tissues based on Hounsfield unit values. Activating the Threshold effect brings up the controls to set the range. Click the 'Threshold' button in the Segment Editor toolbar."
    },
    {
      "step_id": "cb_step_5",
      "title": "Set the Threshold Range",
      "simple": "Adjust the threshold slider to capture bone density values.",
      "detailed": "Bone typically appears with higher CT numbers (e.g., 150–3000 HU). Adjust the range to include the cortical and trabecular bone of the relevant anatomy, such as the glenoid or scapula. This defines the voxels that will be included in the bone segment. Slide the lower and upper bounds appropriately, then click 'Done'."
    },
    {
      "step_id": "cb_step_6",
      "title": "Apply the Threshold",
      "simple": "Click the 'Apply' button to create the initial bone segmentation.",
      "detailed": "Applying the threshold generates a binary mask of the bone within the selected range. This is the foundational step for the bone model. Click 'Apply' in the Threshold effect panel."
    },
    {
      "step_id": "cb_step_7",
      "title": "Open Islands Tool",
      "simple": "Click the 'Islands' button in the Segment Editor to clean up the segmentation.",
      "detailed": "The threshold may capture small disconnected regions (islands) outside the main bone. The Islands effect helps keep only the largest connected bone component. Click the 'Islands' button."
    },
    {
      "step_id": "cb_step_8",
      "title": "Keep Only the Largest Bone Island",
      "simple": "Choose the 'Keep largest island' option to remove extraneous fragments.",
      "detailed": "This retains the main bone structure and discards noise from other tissues (e.g., table, artifacts). It ensures a clean bone model for reconstruction. Select 'Keep largest island' from the Islands options."
    },
    {
      "step_id": "cb_step_9",
      "title": "Apply the Islands Cleanup",
      "simple": "Click the 'Apply' button to finalize the bone segmentation cleanup.",
      "detailed": "This executes the island removal, leaving only the main bone as the active segment. Click 'Apply'."
    },
    {
      "step_id": "cb_step_10",
      "title": "Select the Bone Segment",
      "simple": "Choose the bone segment node you just created as the input for 3D reconstruction.",
      "detailed": "The 3D reconstruction will use this segment to generate a surface model of the bone. This model is essential for visualizing the anatomy and placing the reference fiducial. In the 'Bone segmentation' section, pick the 'Bone_Segment' node."
    },
    {
      "step_id": "cb_step_11",
      "title": "Generate 3D Bone Model",
      "simple": "Click the '3D Reconstruction' button to create a 3D surface from the bone segment.",
      "detailed": "This converts the segmented mask into a 3D surface model that you can rotate and view. The model provides the anatomical reference for subsequent planning. Click the '3D Reconstruction' button in the extension's interface."
    },
    {
      "step_id": "cb_step_12",
      "title": "Orient the 3D View for Glenoid Placement",
      "simple": "Rotate and zoom the 3D view to get a clear line of sight on the glenoid cavity surface.",
      "detailed": "Proper visualization of the glenoid is essential for accurate fiducial placement, which defines the prosthesis center. Adjust the camera angle until the glenoid surface is clearly visible and unobstructed. This step only adjusts the view — do not place any markers."
    },
    {
      "step_id": "cb_step_13",
      "title": "Create a Fiducial Point for Prosthesis Center",
      "simple": "In the Markups module, click 'Point List' and name the new fiducial node 'Prosthesis_center_point'.",
      "detailed": "This fiducial will mark the planned center of the prosthetic implant on the glenoid. Accurate placement is critical for proper alignment and screw trajectory. Switch to the Markups module, create a new point list, and rename it to 'Prosthesis_center_point'."
    },
    {
      "step_id": "cb_step_14",
      "title": "Place the Fiducial on the Glenoid",
      "simple": "Click directly on the glenoid cavity surface in the 3D view to define the prosthesis center point.",
      "detailed": "This point determines the position of the prosthetic implant. Use the 3D model and crosshairs to precisely mark the center of the glenoid. After placing the point, click 'Done' to confirm it."
    },
    {
      "step_id": "cb_step_15",
      "title": "Select the Planner Point",
      "simple": "Choose the 'Prosthesis_center_point' fiducial as the planning reference.",
      "detailed": "The extension will use this point to position the virtual prosthesis. Selecting the correct fiducial ensures the implant aligns with the planned center. In the 'Planning point' section, pick the fiducial node you just created."
    },
    {
      "step_id": "cb_step_16",
      "title": "Perform Prosthesis Implantation",
      "simple": "Click the 'Prosthesis implantation' button to place the virtual prosthesis at the planned center.",
      "detailed": "This automatically positions a prosthesis model in the 3D scene relative to the fiducial point. Review the alignment to see if it matches the surgical plan. Click the 'Prosthesis implantation' button."
    },
    {
      "step_id": "cb_step_17",
      "title": "Decide if Prosthesis Needs Adjustment",
      "simple": "If the prosthesis position looks incorrect, check the 'Adjust Prosthesis (3D transform handles)' box. Otherwise, proceed to Step 20.",
      "detailed": "The virtual prosthesis may need fine-tuning to match the desired orientation and depth. The 3D transform handles allow you to translate and rotate it. Choose 'Yes' to adjust, or 'No' to skip and go directly to planning."
    },
    {
      "step_id": "cb_step_18",
      "title": "Adjust the 3D View for Prosthesis Manipulation",
      "simple": "Rotate and zoom to clearly see the prosthesis and its transform handles.",
      "detailed": "Good visibility is necessary to accurately use the transform handles. Adjust the camera angle so the prosthesis handles are easily accessible. This step only adjusts the view — do not move the handles yet."
    },
    {
      "step_id": "cb_step_19",
      "title": "Confirm Prosthesis Adjustments",
      "simple": "After repositioning the prosthesis with the handles, click 'Update Prosthesis' to apply the changes.",
      "detailed": "This updates the prosthesis model to the new position and orientation, incorporating your manual adjustments. Click the 'Update Prosthesis' button."
    },
    {
      "step_id": "cb_step_20",
      "title": "Generate Screw Plan",
      "simple": "Click the 'Plan' button to compute the optimal screw trajectory based on the prosthesis.",
      "detailed": "The extension will calculate screw paths that secure the prosthesis to the bone, considering bone density and anatomy. This generates the surgical plan. Click the 'Plan' button."
    },
    {
      "step_id": "cb_step_21",
      "title": "Decide if Screw Path Needs Adjustment",
      "simple": "If the planned screw paths require fine-tuning, check the 'Adjust screw' box. Otherwise, the planning is complete.",
      "detailed": "The automatically generated screw paths may need slight modification to avoid critical structures or improve fixation. Choose 'Yes' to adjust endpoints, or 'No' to finalize the plan."
    },
    {
      "step_id": "cb_step_22",
      "title": "Orient the View for Screw Endpoint Editing",
      "simple": "Rotate and zoom to clearly see the screw path endpoints in the 3D view.",
      "detailed": "Clear visualization of the endpoints allows precise manual adjustment of the screw trajectory. Adjust the camera to see the entry and exit points. This step only adjusts the view — do not drag endpoints."
    },
    {
      "step_id": "cb_step_23",
      "title": "Confirm Screw Adjustments",
      "simple": "After manually adjusting the endpoints, click 'Update screw' to apply the changes.",
      "detailed": "This finalizes the screw paths with your modifications. The updated plan is now ready for surgical use. Click the 'Update screw' button."
    }
  ]
}
